import{_ as e,c as a,o,a1 as n}from"./chunks/framework.DILC4Csi.js";const u=JSON.parse('{"title":"OpenAI クォータクエリ | opencode-mystatus","description":"OpenAI ChatGPTの3時間と24時間制限クォータをクエリする方法を学びます。メインウィンドウとセカンダリウィンドウの読み取り方、リセット時間の確認方法を理解します。","frontmatter":{"title":"OpenAI クォータクエリ | opencode-mystatus","sidebarTitle":"OpenAI クォータ","subtitle":"OpenAI クォータクエリ：3時間と24時間制限","description":"OpenAI ChatGPTの3時間と24時間制限クォータをクエリする方法を学びます。メインウィンドウとセカンダリウィンドウの読み取り方、リセット時間の確認方法を理解します。","tags":["OpenAI","クォータクエリ","API クォータ"],"prerequisite":["start-quick-start","start-understanding-output"],"order":1},"headers":[],"relativePath":"ja/vbgate/opencode-mystatus/platforms/openai-usage/index.md","filePath":"ja/vbgate/opencode-mystatus/platforms/openai-usage/index.md"}'),i={name:"ja/vbgate/opencode-mystatus/platforms/openai-usage/index.md"};function l(s,t,r,d,p,c){return o(),a("div",null,[...t[0]||(t[0]=[n(`<h1 id="openai-クォータクエリ-3時間と24時間制限" tabindex="-1">OpenAI クォータクエリ：3時間と24時間制限 <a class="header-anchor" href="#openai-クォータクエリ-3時間と24時間制限" aria-label="Permalink to &quot;OpenAI クォータクエリ：3時間と24時間制限&quot;">​</a></h1><h2 id="学習後のスキル" tabindex="-1">学習後のスキル <a class="header-anchor" href="#学習後のスキル" aria-label="Permalink to &quot;学習後のスキル&quot;">​</a></h2><ul><li><code>/mystatus</code> を使用して OpenAI Plus/Team/Pro サブスクリプションのクォータをクエリする</li><li>出力中の3時間と24時間制限情報を読み取れる</li><li>メインウィンドウとセカンダリウィンドウの違いを理解する</li><li>Token期限切れ時の処理方法を知る</li></ul><h2 id="現在の課題" tabindex="-1">現在の課題 <a class="header-anchor" href="#現在の課題" aria-label="Permalink to &quot;現在の課題&quot;">​</a></h2><p>OpenAIのAPI呼び出しには制限があり、超過すると一時的にアクセスが制限されます。しかし、あなたは以下を知りません：</p><ul><li>現在どれくらい残っているのか？</li><li>3時間と24時間ウィンドウのどちらが使われているのか？</li><li>いつリセットされるのか？</li><li>なぜ時々2つのウィンドウのデータが見られるのか？</li></ul><p>これらの情報をタイムリーに把握しないと、ChatGPTでのコーディングやプロジェクトの進捗に影響するかもしれません。</p><h2 id="いつ使用するか" tabindex="-1">いつ使用するか <a class="header-anchor" href="#いつ使用するか" aria-label="Permalink to &quot;いつ使用するか&quot;">​</a></h2><p>以下の時に使用します：</p><ul><li>OpenAI APIを頻繁に使用して開発する場合</li><li>レスポンスが遅くなったりレート制限がかかったりするのを感じた時</li><li>チームアカウントの使用状況を確認したい時</li><li>いつクォータがリセットされるのか知りたい時</li></ul><h2 id="コアコンセプト" tabindex="-1">コアコンセプト <a class="header-anchor" href="#コアコンセプト" aria-label="Permalink to &quot;コアコンセプト&quot;">​</a></h2><p>OpenAIはAPI呼び出しに対して2つのレート制限ウィンドウを持っています：</p><table tabindex="0"><thead><tr><th>ウィンドウタイプ</th><th>時間</th><th>役割</th></tr></thead><tbody><tr><td><strong>メインウィンドウ</strong>（primary）</td><td>OpenAIサーバーから返される</td><td>短時間の大量呼び出しを防ぐ</td></tr><tr><td><strong>セカンダリウィンドウ</strong>（secondary）</td><td>OpenAIサーバーから返される（存在しない場合あり）</td><td>長期の超過使用を防ぐ</td></tr></tbody></table><p>mystatusはこの2つのウィンドウを並列クエリし、それぞれの以下を表示します：</p><ul><li>使用済みパーセンテージ</li><li>残りクォータプログレスバー</li><li>リセットまでの時間</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>ウィンドウ時間はOpenAIサーバーから返され、異なるサブスクリプションタイプ（Plus、Team、Pro）で異なる場合があります。</p></div><h2 id="実践" tabindex="-1">実践 <a class="header-anchor" href="#実践" aria-label="Permalink to &quot;実践&quot;">​</a></h2><h3 id="ステップ1-クエリコマンドを実行" tabindex="-1">ステップ1：クエリコマンドを実行 <a class="header-anchor" href="#ステップ1-クエリコマンドを実行" aria-label="Permalink to &quot;ステップ1：クエリコマンドを実行&quot;">​</a></h3><p>OpenCodeで <code>/mystatus</code> と入力すると、システムは自動的に設定されたすべてのプラットフォームのクォータをクエリします。</p><p><strong>期待される結果</strong>： OpenAI、Zhipu AI、Z.ai、Copilot、Google Cloudなどすべてのプラットフォームのクォータ情報が表示されます（どのプラットフォームを設定したかによります）。</p><h3 id="ステップ2-openai部分を見つける" tabindex="-1">ステップ2：OpenAI部分を見つける <a class="header-anchor" href="#ステップ2-openai部分を見つける" aria-label="Permalink to &quot;ステップ2：OpenAI部分を見つける&quot;">​</a></h3><p>出力から <code>## OpenAI Account Quota</code> 部分を見つけます。</p><p><strong>期待される結果</strong>： 以下のような内容が表示されます：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>## OpenAI Account Quota</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Account:        user@example.com (plus)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>3-hour limit</span></span>
<span class="line"><span>██████████████░░░░░░░░░ 60% remaining</span></span>
<span class="line"><span>Resets in: 2h 30m</span></span></code></pre></div><h3 id="ステップ3-メインウィンドウ情報を読み取る" tabindex="-1">ステップ3：メインウィンドウ情報を読み取る <a class="header-anchor" href="#ステップ3-メインウィンドウ情報を読み取る" aria-label="Permalink to &quot;ステップ3：メインウィンドウ情報を読み取る&quot;">​</a></h3><p><strong>メインウィンドウ</strong>（primary_window）は通常以下を表示します：</p><ul><li><strong>ウィンドウ名</strong>：<code>3-hour limit</code> または <code>24-hour limit</code> など</li><li><strong>プログレスバー</strong>：残りクォータの割合を直感的に表示</li><li><strong>残りパーセンテージ</strong>：<code>60% remaining</code> など</li><li><strong>リセット時間</strong>：<code>Resets in: 2h 30m</code> など</li></ul><p><strong>期待される結果</strong>：</p><ul><li>ウィンドウ名が時間を表示（3時間 / 24時間）</li><li>プログレスバーは満たされているほど残りが多く、空いているほど使い切れている</li><li>リセット時間はカウントダウンで、ゼロになるとクォータがリセットされる</li></ul><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><code>Limit reached!</code> という表示が見られたら、現在のウィンドウクォータが使い切られたことを意味し、リセットまで待つ必要があります。</p></div><h3 id="ステップ4-セカンダリウィンドウを確認-ある場合" tabindex="-1">ステップ4：セカンダリウィンドウを確認（ある場合） <a class="header-anchor" href="#ステップ4-セカンダリウィンドウを確認-ある場合" aria-label="Permalink to &quot;ステップ4：セカンダリウィンドウを確認（ある場合）&quot;">​</a></h3><p>OpenAIがセカンダリウィンドウデータを返した場合、以下が表示されます：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>24-hour limit</span></span>
<span class="line"><span>███████████████████████████ 90% remaining</span></span>
<span class="line"><span>Resets in: 20h 45m</span></span></code></pre></div><p><strong>期待される結果</strong>：</p><ul><li>セカンダリウィンドウは別の時間次元のクォータを表示（通常24時間）</li><li>メインウィンドウとは異なる残りパーセンテージがある場合がある</li></ul><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>セカンダリウィンドウは独立したクォータプールで、メインウィンドウを使い切ってもセカンダリウィンドウには影響せず、逆もまた然りです。</p></div><h3 id="ステップ5-サブスクリプションタイプを確認" tabindex="-1">ステップ5：サブスクリプションタイプを確認 <a class="header-anchor" href="#ステップ5-サブスクリプションタイプを確認" aria-label="Permalink to &quot;ステップ5：サブスクリプションタイプを確認&quot;">​</a></h3><p><code>Account</code> 行でサブスクリプションタイプが確認できます：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Account:        user@example.com (plus)</span></span>
<span class="line"><span>                                   ^^^^^</span></span>
<span class="line"><span>                                   サブスクリプションタイプ</span></span></code></pre></div><p><strong>よくあるサブスクリプションタイプ</strong>：</p><ul><li><code>plus</code>：個人Plusサブスクリプション</li><li><code>team</code>：チーム/組織サブスクリプション</li><li><code>pro</code>：Proサブスクリプション</li></ul><p><strong>期待される結果</strong>：</p><ul><li>アカウントタイプがメールアドレスの後ろの括弧内に表示されます</li><li>異なるタイプでは制限が異なる場合があります</li></ul><h2 id="チェックポイント-✅" tabindex="-1">チェックポイント ✅ <a class="header-anchor" href="#チェックポイント-✅" aria-label="Permalink to &quot;チェックポイント ✅&quot;">​</a></h2><p>以下を理解したか確認します：</p><table tabindex="0"><thead><tr><th>シナリオ</th><th>期待される結果</th></tr></thead><tbody><tr><td>メインウィンドウが60%残り</td><td>プログレスバーが約60%満たされ、<code>60% remaining</code> と表示</td></tr><tr><td>2.5時間後にリセット</td><td><code>Resets in: 2h 30m</code> と表示</td></tr><tr><td>制限に達した</td><td><code>Limit reached!</code> と表示</td></tr><tr><td>セカンダリウィンドウがある</td><td>メインウィンドウとセカンダリウィンドウにそれぞれ1行のデータが表示</td></tr></tbody></table><h2 id="よくある落とし穴" tabindex="-1">よくある落とし穴 <a class="header-anchor" href="#よくある落とし穴" aria-label="Permalink to &quot;よくある落とし穴&quot;">​</a></h2><h3 id="❌-誤った操作-token期限切れ後にリフレッシュしない" tabindex="-1">❌ 誤った操作：Token期限切れ後にリフレッシュしない <a class="header-anchor" href="#❌-誤った操作-token期限切れ後にリフレッシュしない" aria-label="Permalink to &quot;❌ 誤った操作：Token期限切れ後にリフレッシュしない&quot;">​</a></h3><p><strong>誤った現象</strong>：<code>⚠️ OAuth 認証が期限切れ</code>（日本語）または <code>⚠️ OAuth token expired</code>（英語）という表示が見られる</p><p><strong>原因</strong>：OAuth Token の有効期限が切れており（サーバー側で制御される具体的な時間）、期限切れ後はクォータをクエリできない</p><p><strong>正しい操作</strong>：</p><ol><li>OpenCodeでOpenAIモデルを一度使用する</li><li>Token が自動的にリフレッシュされる</li><li>再度 <code>/mystatus</code> を実行してクエリ</li></ol><h3 id="❌-誤った操作-メインウィンドウとセカンダリウィンドウを混同する" tabindex="-1">❌ 誤った操作：メインウィンドウとセカンダリウィンドウを混同する <a class="header-anchor" href="#❌-誤った操作-メインウィンドウとセカンダリウィンドウを混同する" aria-label="Permalink to &quot;❌ 誤った操作：メインウィンドウとセカンダリウィンドウを混同する&quot;">​</a></h3><p><strong>誤った現象</strong>：1つのウィンドウクォータしかないと思い、メインウィンドウを使い切ってもセカンダリウィンドウがまだ使える</p><p><strong>原因</strong>：2つのウィンドウは独立したクォータプールです。</p><p><strong>正しい操作</strong>：</p><ul><li>2つのウィンドウそれぞれのリセット時間に注目</li><li>メインウィンドウのリセットが速く、セカンダリウィンドウのリセットが遅い</li><li>合理的に使用を分配し、あるウィンドウが長期的に超過するのを避ける</li></ul><h3 id="❌-誤った操作-チームアカウントidを無視する" tabindex="-1">❌ 誤った操作：チームアカウントIDを無視する <a class="header-anchor" href="#❌-誤った操作-チームアカウントidを無視する" aria-label="Permalink to &quot;❌ 誤った操作：チームアカウントIDを無視する&quot;">​</a></h3><p><strong>誤った現象</strong>：Teamサブスクリプションが自分の使用状況を表示していない</p><p><strong>原因</strong>：TeamサブスクリプションではチームアカウントIDを渡す必要がありますが、そうしないとデフォルトアカウントをクエリしている可能性があります。</p><p><strong>正しい操作</strong>：</p><ul><li>OpenCodeで正しいチームアカウントにログインしていることを確認</li><li>Token には自動的に <code>chatgpt_account_id</code> が含まれます</li></ul><h2 id="まとめ" tabindex="-1">まとめ <a class="header-anchor" href="#まとめ" aria-label="Permalink to &quot;まとめ&quot;">​</a></h2><p>mystatusはOpenAI公式APIを呼び出してクォータをクエリします：</p><ul><li>OAuth認証（Plus/Team/Pro）をサポート</li><li>メインウィンドウとセカンダリウィンドウを表示（存在する場合）</li><li>プログレスバーで残りクォータを視覚化</li><li>カウントダウンでリセット時間を表示</li><li>Token期限切れを自動検出</li></ul><h2 id="次のレッスン" tabindex="-1">次のレッスン <a class="header-anchor" href="#次のレッスン" aria-label="Permalink to &quot;次のレッスン&quot;">​</a></h2><blockquote><p>次のレッスンでは <strong><a href="./../zhipu-usage/">Zhipu AIとZ.aiクォータクエリ</a></strong> を学びます。</p><p>学べること：</p><ul><li>5時間Token制限とは何か</li><li>MCP月次クォータの確認方法</li><li>使用率が80%を超えた時の警告表示</li></ul></blockquote><hr><h2 id="付録-ソースコード参照" tabindex="-1">付録：ソースコード参照 <a class="header-anchor" href="#付録-ソースコード参照" aria-label="Permalink to &quot;付録：ソースコード参照&quot;">​</a></h2><details><summary><strong>クリックしてソースコードの場所を展開</strong></summary><blockquote><p>更新日時：2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>機能</th><th>ファイルパス</th><th>行番号</th></tr></thead><tbody><tr><td>OpenAIクォータクエリエントリ</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L207-L236" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>207-236</td></tr><tr><td>OpenAI API呼び出し</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L132-L155" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>132-155</td></tr><tr><td>出力フォーマット</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L164-L194" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>164-194</td></tr><tr><td>JWT Token解析</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L64-L73" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>64-73</td></tr><tr><td>ユーザーメール抽出</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L78-L81" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>78-81</td></tr><tr><td>Token期限切れチェック</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/openai.ts#L216-L221" target="_blank" rel="noreferrer"><code>plugin/lib/openai.ts</code></a></td><td>216-221</td></tr><tr><td>OpenAIAuthData型定義</td><td><a href="https://github.com/vbgate/opencode-mystatus/blob/main/plugin/lib/types.ts#L28-L33" target="_blank" rel="noreferrer"><code>plugin/lib/types.ts</code></a></td><td>28-33</td></tr></tbody></table><p><strong>重要な定数</strong>：</p><ul><li><code>OPENAI_USAGE_URL = &quot;https://chatgpt.com/backend-api/wham/usage&quot;</code>：OpenAI公式クォータクエリAPI</li></ul><p><strong>重要な関数</strong>：</p><ul><li><code>queryOpenAIUsage(authData)</code>：OpenAIクォータをクエリするメイン関数</li><li><code>fetchOpenAIUsage(accessToken)</code>：OpenAI APIを呼び出す</li><li><code>formatOpenAIUsage(data, email)</code>：出力をフォーマットする</li><li><code>parseJwt(token)</code>：JWT Tokenを解析（非標準ライブラリ実装）</li><li><code>getEmailFromJwt(token)</code>：Tokenからユーザーメールを抽出</li><li><code>getAccountIdFromJwt(token)</code>：TokenからチームアカウントIDを抽出</li></ul></details>`,70)])])}const b=e(i,[["render",l]]);export{u as __pageData,b as default};
